import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState({
    totalQueries: 0,
    avgResponseTime: 0,
    totalTime: 0
  });
  const [responseTime, setResponseTime] = useState(0);

  const askQuestion = async () => {

    if (!question) return;

    setLoading(true);
    const startTime = Date.now();

    try {

      const response = await axios.post(
        "http://127.0.0.1:5000/ask",
        { question: question }
      );

      const endTime = Date.now();
      const time = endTime - startTime;
      setResponseTime(time);

      setAnswer(response.data.answer);

      // Update stats
      setStats(prev => ({
        totalQueries: prev.totalQueries + 1,
        totalTime: prev.totalTime + time,
        avgResponseTime: (prev.totalTime + time) / (prev.totalQueries + 1)
      }));

      setQuestion("");

    } catch (error) {

      setAnswer("Error connecting to backend.");

    }

    setLoading(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && e.ctrlKey) {
      askQuestion();
    }
  };

  return (
    <div className="app-wrapper">
      <div className="container">

        <div className="header">
          <div className="logo-section">
            <div className="logo">📡</div>
            <div>
              <div className="title" data-text="RAN Assistant Pro">RAN Assistant Pro</div>
              <div className="subtitle">
                Intelligent Telecom RAN Support System
              </div>
            </div>
          </div>
        </div>

        <div className="stats-dashboard">
          <div className="stat-card">
            <div className="stat-label">Total Queries</div>
            <div className="stat-value">{stats.totalQueries}</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Avg Response Time</div>
            <div className="stat-value">{stats.avgResponseTime.toFixed(0)}ms</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Last Response</div>
            <div className="stat-value">{responseTime}ms</div>
          </div>
          <div className="stat-card">
            <div className="stat-label">Model</div>
            <div className="stat-value model-name">llama-3.3-70b</div>
          </div>
        </div>

        <div className="input-section">
          <label className="input-label">Ask Your Question</label>
          <textarea
            rows="5"
            placeholder="Ask telecom questions like:
• What is 5G RAN?
• Explain network slicing
• How does network densification support 5G?
(Press Ctrl+Enter to submit)"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            onKeyPress={handleKeyPress}
            className="input-textarea"
          />

          <div className="button-group">
            <button 
              onClick={askQuestion}
              disabled={loading || !question.trim()}
              className="btn-primary"
            >
              {loading ? "⏳ Generating..." : "🤖 Ask AI"}
            </button>
            <button 
              onClick={() => { setQuestion(""); setAnswer(""); }}
              className="btn-secondary"
            >
              Clear
            </button>
          </div>
        </div>

        {loading && (
          <div className="loading-container">
            <div className="spinner"></div>
            <div className="loading-text">Generating Answer...</div>
          </div>
        )}

        {answer && !loading && (
          <div className="answer-section">
            <div className="answer-header">
              <span className="answer-icon">✨</span>
              <span>AI Response</span>
              <span className="response-time">Response Time: {responseTime}ms</span>
            </div>
            <div className="answer-box">
              {answer}
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

export default App;
